var partitionString = function(s) {
    const res = [];
    const seen = new Set();
    let cur = '';
    for (const ch of s) {
        cur += ch;
        if (!seen.has(cur)) {
            res.push(cur);
            seen.add(cur);
            cur = '';
        }
    }
    return res;
};
